// Pantalla principal del bot
const d = $input.first().json;
const respuesta =
  '👋 ¡Hola ' + d.nombre + '! Soy TutorBot, tu asistente de asesorías académicas.\n\n' +
  'Elige una opción respondiendo con el número:\n\n' +
  '1️⃣ Solicitar tutoría\n' +
  '2️⃣ Consultar mis solicitudes\n' +
  '3️⃣ Cancelar una tutoría\n\n' +
  'También puedes usar /solicitar, /consultar o /cancelar.';
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user, respuesta,
  pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}' } }];

// Valida la tutoria elegida para cancelar
const d = $input.first().json;
const lista = (d.datos && d.datos.cancelables) || [];
const n = parseInt(d.texto, 10);
if (!n || n < 1 || n > lista.length) {
  return [{ json: { accion: 'reintentar', chat_id: d.chat_id, telegram_user: d.telegram_user,
    respuesta: '⚠️ Opción no válida. Responde con un número entre 1 y ' + lista.length + '.',
    pantalla_actual: 'cancelar', paso_actual: 'seleccion', datos_parciales: JSON.stringify(d.datos || {}) } }];
}
const sel = lista[n - 1];
return [{ json: { accion: 'cancelar', chat_id: d.chat_id, telegram_user: d.telegram_user, nombre: d.nombre,
  respuesta: '✅ Tutoría cancelada: ' + sel.materia + ' — ' + sel.fecha + ' ' + sel.hora +
    '.\nEl horario del tutor quedó libre nuevamente.\n\nEscribe /start para volver al menú.',
  pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}',
  id_tutoria: sel.id_tutoria, id_tutor: sel.id_tutor, id_dispo: sel.id_dispo,
  materia: sel.materia, fecha: sel.fecha, hora: sel.hora } }];

// Paso 1 del wizard: lista numerada de materias segun tutores activos
const d = $('Motor de Estados').first().json;
const tutores = $input.all().map(i => i.json).filter(t => t.id_tutor && String(t.estado || '').toLowerCase() === 'activo');
const set = new Set();
tutores.forEach(t => String(t.especialidad_materias || '').split(',').forEach(x => { const v = x.trim(); if (v) set.add(v); }));
const materias = [...set].sort();
if (!materias.length) {
  return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
    respuesta: '😔 Por ahora no hay materias con tutores activos. Intenta más tarde.',
    pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}' } }];
}
const lista = materias.map((m, i) => (i + 1) + '. ' + m).join('\n');
const respuesta = '📚 Materias disponibles:\n\n' + lista + '\n\nResponde con el número de la materia que necesitas.';
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user, respuesta,
  pantalla_actual: 'solicitar', paso_actual: 'materia', datos_parciales: JSON.stringify({ materias }) } }];

// Paso 4 del wizard: procesa la confirmacion del estudiante
const d = $input.first().json;
const datos = d.datos || {};
const c = datos.candidato;
const t = (d.texto || '').trim().toLowerCase();
if (!c) {
  return [{ json: { accion: 'reintentar', chat_id: d.chat_id, telegram_user: d.telegram_user,
    respuesta: '🤖 Tu sesión expiró. Escribe /start para comenzar de nuevo.',
    pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}' } }];
}
if (t === '1' || t === 'si' || t === 'sí' || t === 'confirmar') {
  const aviso_tutor = '📌 Nueva tutoría asignada\n\n👤 Estudiante: ' + d.nombre +
    '\n📚 Materia: ' + datos.materia + '\n📅 Fecha: ' + datos.fecha +
    '\n🕐 Horario: ' + c.hora + '\n🆔 ' + datos.id_tutoria;
  const respuesta = '🎉 ¡Tutoría confirmada y asignada!\n\n👨‍🏫 ' + c.nombre_tutor +
    '\n📚 ' + datos.materia + '\n📅 ' + datos.fecha + '\n🕐 ' + c.hora + '\n🆔 ' + datos.id_tutoria +
    '\n\nRecibirás un recordatorio el día de tu asesoría. Escribe /start para volver al menú.';
  return [{ json: { accion: 'confirmar', chat_id: d.chat_id, telegram_user: d.telegram_user, respuesta,
    pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}',
    id_tutoria: datos.id_tutoria, id_dispo: c.id_dispo, telegram_tutor: c.telegram_tutor, aviso_tutor } }];
}
if (t === '2' || t === 'no' || t === 'descartar') {
  return [{ json: { accion: 'descartar', chat_id: d.chat_id, telegram_user: d.telegram_user,
    respuesta: '❌ Solicitud descartada. El horario sigue libre para otros estudiantes.\n\nEscribe /start para volver al menú.',
    pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}', id_tutoria: datos.id_tutoria } }];
}
return [{ json: { accion: 'reintentar', chat_id: d.chat_id, telegram_user: d.telegram_user,
  respuesta: '⚠️ Responde 1️⃣ para confirmar o 2️⃣ para descartar.',
  pantalla_actual: 'solicitar', paso_actual: 'confirmacion', datos_parciales: JSON.stringify(datos) } }];

// Genera recordatorios del dia y detecta tutorias vencidas para finalizar
const tutorias = $('Leer Tutorias Dia').all().map(i => i.json).filter(r => r.id_tutoria);
const tutores = $input.all().map(i => i.json).filter(t => t.id_tutor);
const mapaTutores = {};
tutores.forEach(t => { mapaTutores[String(t.id_tutor)] = t; });
const hoyD = new Date(); hoyD.setHours(0, 0, 0, 0);
const hoyStr = hoyD.getFullYear() + '-' + String(hoyD.getMonth() + 1).padStart(2, '0') + '-' + String(hoyD.getDate()).padStart(2, '0');
const out = [];
for (const r of tutorias) {
  const f = new Date(r.fecha + 'T00:00:00');
  const tutor = mapaTutores[String(r.id_tutor)] || {};
  if (r.fecha === hoyStr && ['Asignada', 'Confirmada'].includes(r.estado)) {
    out.push({ json: { tipo: 'recordatorio', chat_id: String(r.id_estudiante),
      mensaje: '⏰ Recordatorio: hoy tienes tutoría de ' + r.materia + ' a las ' + r.hora +
        ' con ' + (tutor.nombre || r.id_tutor) + '. 🆔 ' + r.id_tutoria, id_tutoria: r.id_tutoria } });
    if (tutor.telegram_chat_id) {
      out.push({ json: { tipo: 'recordatorio', chat_id: String(tutor.telegram_chat_id),
        mensaje: '⏰ Recordatorio: hoy tienes una tutoría de ' + r.materia + ' a las ' + r.hora +
          '. 🆔 ' + r.id_tutoria, id_tutoria: r.id_tutoria } });
    }
  }
  if (f < hoyD && ['Asignada', 'Confirmada'].includes(r.estado)) {
    out.push({ json: { tipo: 'finalizar', id_tutoria: r.id_tutoria, id_dispo: r.id_dispo || '' } });
  }
}
return out;

// Motor de asignacion: cruza materia + dia de la semana + horario libre
const d = $('Validar Fecha').first().json;
const norm = s => String(s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').trim();
const materia = d.datos.materia;
const tutores = $('Leer Tutores Busqueda').all().map(i => i.json)
  .filter(t => t.id_tutor && String(t.estado || '').toLowerCase() === 'activo')
  .filter(t => String(t.especialidad_materias || '').split(',').map(x => norm(x)).includes(norm(materia)));
const dias = ['domingo', 'lunes', 'martes', 'miercoles', 'jueves', 'viernes', 'sabado'];
const diaSemana = dias[new Date(d.fecha + 'T00:00:00').getDay()];
const dispo = $input.all().map(i => i.json)
  .filter(x => x.id_dispo && norm(x.estado) === 'libre' && norm(x.dia_semana) === diaSemana);
let candidato = null;
for (const t of tutores) {
  const slot = dispo.find(s => String(s.id_tutor) === String(t.id_tutor));
  if (slot) { candidato = { tutor: t, slot }; break; }
}
const bonito = diaSemana.charAt(0).toUpperCase() + diaSemana.slice(1);
if (!candidato) {
  return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user, hayCandidato: false,
    respuesta: '😔 No hay tutores de ' + materia + ' con horario libre el ' + bonito + ' ' + d.fecha +
      '.\n\n📅 Escribe otra fecha (YYYY-MM-DD) o /start para volver al menú.',
    pantalla_actual: 'solicitar', paso_actual: 'fecha', datos_parciales: JSON.stringify(d.datos || {}) } }];
}
const id_tutoria = 'TUT-' + Date.now();
const hora = candidato.slot.hora_inicio + ' - ' + candidato.slot.hora_fin;
const respuesta = '🎓 ¡Tutor encontrado!\n\n' +
  '👨‍🏫 Tutor: ' + candidato.tutor.nombre + '\n' +
  '📚 Materia: ' + materia + '\n' +
  '📅 Fecha: ' + d.fecha + ' (' + bonito + ')\n' +
  '🕐 Horario: ' + hora + '\n\n' +
  '1️⃣ Confirmar\n2️⃣ Descartar';
const datos = { materia, fecha: d.fecha, id_tutoria,
  candidato: { id_tutor: candidato.tutor.id_tutor, nombre_tutor: candidato.tutor.nombre,
    telegram_tutor: candidato.tutor.telegram_chat_id || '', id_dispo: candidato.slot.id_dispo, hora } };
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user, nombre: d.nombre, hayCandidato: true,
  respuesta, pantalla_actual: 'solicitar', paso_actual: 'confirmacion', datos_parciales: JSON.stringify(datos),
  id_tutoria, id_estudiante: d.telegram_user, id_tutor: candidato.tutor.id_tutor,
  materia, fecha: d.fecha, hora, estado: 'Solicitada', id_dispo: candidato.slot.id_dispo } }];

// Muestra el historial de tutorias del estudiante
const d = $('Motor de Estados').first().json;
const filas = $input.all().map(i => i.json).filter(r => r.id_tutoria);
if (!filas.length) {
  return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
    respuesta: '📭 No tienes tutorías registradas todavía.\n\nEscribe /solicitar para pedir tu primera asesoría.',
    pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}' } }];
}
const iconos = { 'Solicitada': '🟡', 'Asignada': '🔵', 'Confirmada': '🟢', 'Finalizada': '✅', 'Cancelada': '❌' };
const lista = filas.map(r => (iconos[r.estado] || '▫️') + ' ' + r.materia + ' — ' + r.fecha + ' ' + r.hora +
  '\n   Estado: ' + r.estado + ' | Tutor: ' + r.id_tutor + ' | ' + r.id_tutoria).join('\n\n');
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
  respuesta: '📋 Tus tutorías:\n\n' + lista + '\n\nEscribe /start para volver al menú.',
  pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}' } }];

// Busca el chat de Telegram del tutor y arma el aviso de cancelacion
const d = $('Validar Cancelacion').first().json;
const tutor = $input.all().map(i => i.json).find(t => t.id_tutor) || {};
const telegram_tutor = tutor.telegram_chat_id || '';
const aviso_tutor = '❌ Tutoría cancelada por el estudiante\n\n👤 ' + (d.nombre || d.telegram_user) +
  '\n📚 ' + d.materia + '\n📅 ' + d.fecha + ' ' + d.hora + '\n🆔 ' + d.id_tutoria +
  '\n\nTu horario quedó libre nuevamente.';
return [{ json: { ...d, telegram_tutor, aviso_tutor } }];

// Lista numerada de tutorias activas que se pueden cancelar
const d = $('Motor de Estados').first().json;
const hoy = new Date(); hoy.setHours(0, 0, 0, 0);
const activas = $input.all().map(i => i.json).filter(r => r.id_tutoria &&
  ['Solicitada', 'Asignada', 'Confirmada'].includes(r.estado) &&
  new Date(r.fecha + 'T00:00:00') >= hoy);
if (!activas.length) {
  return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
    respuesta: '📭 No tienes tutorías activas para cancelar.\n\nEscribe /start para volver al menú.',
    pantalla_actual: 'menu', paso_actual: '', datos_parciales: '{}' } }];
}
const lista = activas.map((r, i) => (i + 1) + '. ' + r.materia + ' — ' + r.fecha + ' ' + r.hora + ' (' + r.estado + ')').join('\n');
const cancelables = activas.map(r => ({ id_tutoria: r.id_tutoria, id_tutor: r.id_tutor,
  id_dispo: r.id_dispo || '', materia: r.materia, fecha: r.fecha, hora: r.hora, estado: r.estado }));
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
  respuesta: '🗑️ ¿Cuál tutoría deseas cancelar?\n\n' + lista + '\n\nResponde con el número.',
  pantalla_actual: 'cancelar', paso_actual: 'seleccion', datos_parciales: JSON.stringify({ cancelables }) } }];

// Combina el mensaje con la sesion guardada y decide la ruta (maquina de estados)
const m = $('Normalizar Mensaje').first().json;
const filas = $input.all().map(i => i.json).filter(r => r && r.telegram_user);
const ses = filas.length ? filas[0] : { pantalla_actual: '', paso_actual: '', datos_parciales: '' };
let datos = {};
try { datos = ses.datos_parciales ? JSON.parse(ses.datos_parciales) : {}; } catch (e) { datos = {}; }
const t = (m.texto || '').toLowerCase();
let ruta = 'menu';
if (t === '/start' || t === '/menu' || t === 'menu' || t === '/ayuda') {
  ruta = 'menu';
} else if (t === '/solicitar') {
  ruta = 'inicio_solicitud';
} else if (t === '/consultar') {
  ruta = 'consultar';
} else if (t === '/cancelar') {
  ruta = 'cancelar_lista';
} else if (ses.pantalla_actual === 'solicitar' && ses.paso_actual === 'materia') {
  ruta = 'capturar_materia';
} else if (ses.pantalla_actual === 'solicitar' && ses.paso_actual === 'fecha') {
  ruta = 'capturar_fecha';
} else if (ses.pantalla_actual === 'solicitar' && ses.paso_actual === 'confirmacion') {
  ruta = 'confirmar';
} else if (ses.pantalla_actual === 'cancelar' && ses.paso_actual === 'seleccion') {
  ruta = 'cancelar_exec';
} else {
  if (t === '1') ruta = 'inicio_solicitud';
  else if (t === '2') ruta = 'consultar';
  else if (t === '3') ruta = 'cancelar_lista';
  else ruta = 'menu';
}
return [{ json: { ...m, ruta, datos } }];

// Extrae los datos relevantes del mensaje de Telegram
const update = $input.first().json;
const msg = update.message || {};
const chat_id = msg.chat ? msg.chat.id : null;
const texto = (msg.text || '').trim();
const from = msg.from || {};
const nombre = [from.first_name, from.last_name].filter(Boolean).join(' ') || from.username || 'Estudiante';
const telegram_user = String(from.id || chat_id || '');
return [{ json: { chat_id, texto, nombre, telegram_user } }];

// Paso 2 del wizard: valida la materia elegida y pide la fecha
const d = $input.first().json;
const materias = (d.datos && d.datos.materias) || [];
const n = parseInt(d.texto, 10);
if (!n || n < 1 || n > materias.length) {
  return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
    respuesta: '⚠️ Opción no válida. Responde con un número entre 1 y ' + materias.length + '.',
    pantalla_actual: 'solicitar', paso_actual: 'materia', datos_parciales: JSON.stringify(d.datos || {}) } }];
}
const materia = materias[n - 1];
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
  respuesta: '✅ Materia seleccionada: ' + materia + '\n\n📅 Ahora escribe la fecha deseada en formato YYYY-MM-DD (ejemplo: 2026-07-15).',
  pantalla_actual: 'solicitar', paso_actual: 'fecha', datos_parciales: JSON.stringify({ materia }) } }];

// Paso 3 del wizard: valida formato y que la fecha no sea pasada
const d = $input.first().json;
const t = (d.texto || '').trim();
let fechaValida = false;
let respuesta = '';
if (!/^\d{4}-\d{2}-\d{2}$/.test(t)) {
  respuesta = '⚠️ Formato de fecha inválido. Usa YYYY-MM-DD (ejemplo: 2026-07-15).';
} else {
  const f = new Date(t + 'T00:00:00');
  const hoy = new Date(); hoy.setHours(0, 0, 0, 0);
  if (isNaN(f.getTime())) respuesta = '⚠️ Esa fecha no existe. Intenta de nuevo (YYYY-MM-DD).';
  else if (f < hoy) respuesta = '⚠️ La fecha no puede estar en el pasado. Intenta con otra fecha.';
  else fechaValida = true;
}
return [{ json: { ...d, fecha: t, fechaValida, respuesta,
  pantalla_actual: 'solicitar', paso_actual: 'fecha', datos_parciales: JSON.stringify(d.datos || {}) } }];

// Reporte semanal para la coordinacion academica
const COORDINADOR_CHAT_ID = 'PON_AQUI_EL_CHAT_ID_DEL_COORDINADOR';
const tutorias = $('Leer Tutorias Semana').all().map(i => i.json).filter(r => r.id_tutoria);
const tutores = $input.all().map(i => i.json).filter(t => t.id_tutor);
const mapaTutores = {};
tutores.forEach(t => { mapaTutores[String(t.id_tutor)] = t.nombre; });
const hoy = new Date(); hoy.setHours(0, 0, 0, 0);
const hace7 = new Date(hoy.getTime() - 7 * 24 * 60 * 60 * 1000);
const semana = tutorias.filter(r => { const f = new Date(r.fecha + 'T00:00:00'); return f >= hace7 && f < hoy; });
const conteo = {}; const porMateria = {}; const porTutor = {};
for (const r of semana) {
  conteo[r.estado] = (conteo[r.estado] || 0) + 1;
  porMateria[r.materia] = (porMateria[r.materia] || 0) + 1;
  const nt = mapaTutores[String(r.id_tutor)] || r.id_tutor;
  porTutor[nt] = (porTutor[nt] || 0) + 1;
}
const linea = obj => Object.entries(obj).map(([k, v]) => '   • ' + k + ': ' + v).join('\n') || '   • Sin registros';
const mensaje = '📊 REPORTE SEMANAL — TutorBot\n' +
  '🗓️ Semana: ' + hace7.toISOString().slice(0, 10) + ' a ' + hoy.toISOString().slice(0, 10) + '\n\n' +
  '📌 Total de tutorías: ' + semana.length + '\n\n' +
  '📈 Por estado:\n' + linea(conteo) + '\n\n' +
  '📚 Por materia:\n' + linea(porMateria) + '\n\n' +
  '👨‍🏫 Por tutor:\n' + linea(porTutor) + '\n\n' +
  '🤖 Generado automáticamente por TutorBot.';
return [{ json: { chat_id: COORDINADOR_CHAT_ID, mensaje } }];

// Normaliza la salida comun: respuesta al estudiante + estado de la sesion
const d = $input.first().json;
return [{ json: {
  chat_id: d.chat_id,
  telegram_user: d.telegram_user || String(d.chat_id || ''),
  respuesta: d.respuesta || '🤖 No entendí tu mensaje. Escribe /start para ver el menú.',
  pantalla_actual: d.pantalla_actual || '',
  paso_actual: d.paso_actual || '',
  datos_parciales: typeof d.datos_parciales === 'string' ? d.datos_parciales : JSON.stringify(d.datos_parciales || {})
} }];
